     nexacro._YearComboControl = function (id, left, top, width, height, right, bottom, minwidth, maxwidth, minheight, maxheight, parent)
    {
        nexacro.Combo.call(this, id, left, top, width, height, right, bottom, minwidth, maxwidth, minheight, maxheight, parent);
    };

    var _pYearComboControl = nexacro._createPrototype(nexacro.Combo, nexacro._YearComboControl);
    nexacro._YearComboControl.prototype = _pYearComboControl;
