    _pYearComboControl.on_create_contents = function ()
    {
        nexacro.Combo.prototype.on_create_contents.call(this);
        //this.set_type("filterlike");
        var dataset = this._innerdataset = new nexacro.Dataset("year" + this.id);
        dataset._setContents({"ColumnInfo" : {"Column" : [ {"id" : "CODE","type" : "STRING","size" : "256"},{"id" : "DATA","type" : "STRING","size" : "256"}]}});

        let current_year = new Date().getFullYear();
        var startyear = current_year - 100;
        var endyear = current_year + 100;
        var j=0;
        for (var i =startyear; i <= endyear; i++)
        {
            dataset.addRow();
            dataset.setColumn(j,0,i);
            dataset.setColumn(j,1,i);
            j++;
        }
        
        this.set_codecolumn("CODE");
        this.set_datacolumn("DATA");
        this.on_apply_innerdataset(dataset);
    };

