	_pCalendar._convertValueType = function (v, dateobj, bapplyrule)
	{
		var ret, datatyperule;
		if (bapplyrule)
		{
			datatyperule = this._env._p_datatyperule;
			if (datatyperule == "1.0")
				return v;
		}

		ret = (dateobj === undefined || dateobj === null) ? dateobj : nexacro._toString(dateobj);

		return ret;
	};

