        this._history = [];

        this._image_format = ["bmp", "gif", "jpeg", "jpg", "png", "tif", "tiff", "icon"];


        this._default_stroke_style = nexacro.ColorObject("black");
        this._currentPath = [];

        this._path_style = {};
