        "oninit": 1, "onclick": 1, "ondblclick": 1,
        "onkillfocus": 1, "onsetfocus": 1,
        "ontouch": 1, "ontouchstart": 1, "ontouchmove": 1, "ontouchend": 1,
        "onlbuttondown": 1, "onlbuttonup": 1, "onmousemove": 1, "onload": 1, "onerror": 1, "onsuccess": 1,
