    _pCellInfo.set_expr = function (v)
    {
        if (v != this._p_expr._value)
        {
            var str;
            if (typeof v !== 'string')
                str = v.toString();
            else
                str = v;

            var tag = str.substr(0, 4).toUpperCase();
            if (tag != "" && tag != "EXPR")
                v = "EXPR:" + v;
            this._p_expr._set(v);
            this._afterProcBindTypeProp();
        }
    };

