    _pAbstractComponent.set_cssclass = function (val)
	{
		if (this._p_cssclass != val)
		{
			this._p_cssclass = val;
			this._setPropertyMap("cssclass", val);
			if(this._ctrlobj)
				this._setControlSpecificProperty("cssclass");
		}
	};
    
