	// genie : 필요한가?
	_pAbstractSelectAny.on_get_css_assumedtypename = function ()
	{
		if (this._p_selectmulticombo)
			return "MultiCombo";
		else if (this._p_selectcheckboxset)
			return "CheckboxSet";
		else if (this._p_selectlistbox)
			return "ListBox";

		return this._type_name; // genie : default return 값을 어떻게 가져갈까? 
	};
